export const SOFTWARE_LIST: Software[] = S;
export function getSoftwareBySlug(slug:string){ return S.find(s=>s.slug===slug); }
export function getSoftwareByCategory(cat:string){ return S.filter(s=>s.category===cat); }
export function getSoftwareByPlatform(plat:string){ return S.filter(s=>s.platform.includes(plat)); }
export function searchSoftware(q:string){ const l=q.toLowerCase(); return S.filter(s=>s.name.toLowerCase().includes(l)||s.description.toLowerCase().includes(l)||s.tags.some(t=>t.includes(l))||s.category.includes(l)); }
